import json  # JSON encoder/decoder module
from urllib import request as req  # Allows Python to open and read from a URL.


def main():
    """Main Function"""

    config = {
        'services': [
            {'name':'demo-srv1','url':'http://localhost:5002'}

        ],
         'routes':[
            {'path': '/demo',
             'methods': ['POST'],  # Supports any method
             'service':'demo-srv1'

            }
          ]
    }

    # Encode JSON into UTF8 format.
    json_data = bytes(json.dumps(config), encoding="utf-8")


    # Configure request parameters
    req_headers = {'Content-Type': 'application/json'}

    # Set up the request object and send data using POST method with
    # Request Headers
    apiEndpoint = f'http://localhost:8001/services/'
    request = req.Request(url=apiEndpoint,
                          data=json_data, headers=req_headers)

    resp = req.urlopen(request).read()  # Sends the request and retrieves response

    print('RESPONSE:\n', json.loads(resp))


if __name__ == '__main__':
    main()

